using System.Collections.Generic;
using UnityEngine;

/// <summary>Operador de comparação usado por condições numéricas (mortes na área, população da vila, variáveis, etc.).</summary>
public enum Comparison
{
    Equal,
    NotEqual,
    Greater,
    GreaterOrEqual,
    Less,
    LessOrEqual
}

public static class NpcConditionUtil
{
    public static bool Compare(int actual, Comparison comparison, int target)
    {
        switch (comparison)
        {
            case Comparison.Equal: return actual == target;
            case Comparison.NotEqual: return actual != target;
            case Comparison.Greater: return actual > target;
            case Comparison.GreaterOrEqual: return actual >= target;
            case Comparison.Less: return actual < target;
            case Comparison.LessOrEqual: return actual <= target;
            default: return false;
        }
    }

    /// <summary>Como Compare, mas para floats (Equal/NotEqual usam Mathf.Approximately para evitar problemas de precisão).</summary>
    public static bool CompareFloat(float actual, Comparison comparison, float target)
    {
        switch (comparison)
        {
            case Comparison.Equal: return Mathf.Approximately(actual, target);
            case Comparison.NotEqual: return !Mathf.Approximately(actual, target);
            case Comparison.Greater: return actual > target;
            case Comparison.GreaterOrEqual: return actual >= target;
            case Comparison.Less: return actual < target;
            case Comparison.LessOrEqual: return actual <= target;
            default: return false;
        }
    }

    /// <summary>
    /// Avalia uma lista de <see cref="NpcCondition"/> (lista vazia ou nula =
    /// verdadeiro). Se "requireAll" estiver activo, TODAS as condições têm de
    /// se cumprir; senão, basta UMA. Usado por Action_ConditionalBranch e pela
    /// conclusão automática de tarefas de missão (MissionTask.autoCompleteConditions
    /// / MissionManager). "npc" pode ser null — a maioria das condições não
    /// depende de um NpcController específico (lêem PlayerProgress/GameVariables/
    /// WorldState directamente); condições que precisam do NPC (ex:
    /// Condition_PlayerForm) tratam "npc == null" de forma segura.
    /// </summary>
    public static bool EvaluateConditions(List<NpcCondition> conditions, bool requireAll, NpcController npc)
    {
        if (conditions == null || conditions.Count == 0) return true;

        bool any = false;

        foreach (var condition in conditions)
        {
            if (condition == null) continue;

            bool ok = condition.Evaluate(npc);

            if (requireAll && !ok) return false;
            if (!requireAll && ok) any = true;
        }

        return requireAll || any;
    }
}
